let isActiveMenu = !1; const burgerMenu = document.querySelector(".burger-menu"); burgerMenu.addEventListener("click", burgerMenuLogic); const menuWrapper = document.querySelector(".header__mobile-wrapper"); function closeMenu() { burgerMenu.classList.remove("_active"), document.querySelector(".header-menu").classList.remove("_active"), document.body.classList.remove("_lock"), isActiveMenu = !1 } function burgerMenuLogic() { burgerMenu.classList.toggle("_active"), document.querySelector(".header-menu").classList.toggle("_active"), document.body.classList.toggle("_lock"), isActiveMenu = !isActiveMenu } menuWrapper.addEventListener("click", e => { let r = e.target, s = window.innerWidth; !isActiveMenu || (s > 700 ? r.closest(".header-menu__list") || closeMenu() : r.closest(".header__mobile-body") || closeMenu()) }); const clearReseizeBlocks = document.querySelectorAll("[data-clear-transition]"); if (clearReseizeBlocks) { let e; function r() { clearReseizeBlocks.forEach(e => { e.classList.add("--resize-animation-stopper") }), clearTimeout(e), e = setTimeout(() => { clearReseizeBlocks.forEach(e => { e.classList.remove("--resize-animation-stopper") }) }, 200) } window.addEventListener("resize", r) }
